{"name":"get","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Http.Controllers.appointmentController.appointmentController.get","label":"Method","file_path":"/Users/naman/Documents/QBApps/qbapi/app/Http/Controllers/appointmentController.php","start_line":31,"end_line":165,"source":"    public function get(Request $request,$chainID)
    {
        $listOfChainsTable = Constants::getGlobalTableName("listOfChains");
        $getChainSettings = convertToArray(DB::table($listOfChainsTable)->where('chainID', $chainID)->get());
        if (empty($getChainSettings)) {
            $status["status"] = false;
            $status["message"] = "Invalid chainID";
            return $status;
        }
        $industry = $getChainSettings[0]["industry"];
        if ($industry != 'SPA_AND_SALON') {
            $status["status"] = false;
            $status["message"] = "Invalid chain industry";
            return $status;
        }

        $today = date('Y-m-d');
        $dateObject = new Datetime($today);
        $fromDate = $dateObject->modify("-".'7'." days")->format('Y-m-d');
        $toDate = $today;
        if(isset($request->fromDate)){
            $fromDate = $request->fromDate;
        }
        if(isset($request->toDate)){
            $toDate = $request->toDate;
        }

        if(isset($request->customerID)){
            $customerID = $request->customerID;
        }else{
            $customerID = '%';
        }

        if(isset($request->appointmentID)){
            $appointmentID = $request->appointmentID;
        }else{
            $appointmentID = '%';
        }

        if(isset($request->deviceID)){
            $deviceID = $request->deviceID;
        }else{
            $deviceID = '%';
        }

        if(isset($request->storeID)){
            $storeID = $request->storeID;
        }else{
            $storeID = '%';
        }

        $requestedAll = 0;
        if(isset($request->requestedAll)){
            $requestedAll = 1;
        }

        $getAppointmentSummaryTable = Constants::getChainTableName($chainID,'appointmentSummary');
        $getAppointmentDetailTable = Constants::getChainTableName($chainID,'appointmentDetail');
        $getCustomerTable = Constants::getChainTableName($chainID,'customers');

        $usersTable = Constants::getGlobalTableName('users');
        $userStoreMap = Constants::getGlobalTableName('userStoreMap');

        $rolesTable = Constants::getChainTableName($chainID,'roles');

        if($requestedAll){
            $appointmentSummary = DB::table($getAppointmentSummaryTable)->where('isActive',1)
                                ->where('customerID','like',"$customerID")
                                ->where('appointmentID','like',"$appointmentID")
                                ->where('storeID','like',"$storeID")
                                ->get();
        }else{
            $appointmentSummary = DB::table($getAppointmentSummaryTable)->where('isActive',1)
                                ->whereDate('startTimeLocal','>=',(string)$fromDate)
                                ->whereDate('endTimeLocal','<=',(string)$toDate)
                                ->where('customerID','like',"$customerID")
                                ->where('appointmentID','like',"$appointmentID")
                                ->where('deviceID','like',"$deviceID")
                                ->where('storeID','like',"$storeID")
                                ->get();
        }


        $appointmentDetail = DB::table($getAppointmentDetailTable)->get();
        $customers = DB::table($getCustomerTable)->get();
        // $role = DB::table($rolesTable)->where('roleName','Staff')->where('isActive',1)->first();
        $staffs = DB::table($usersTable)
                         ->select("$usersTable.firstName","$usersTable.middleName","$usersTable.lastName","$usersTable.email","$usersTable.ID")
                         ->join($userStoreMap,"$usersTable.ID","=","$userStoreMap.userID")
                         ->where('chainID',$chainID)
                         ->where("$usersTable.isActive",1)
                        // ->where('roleID',$role->roleID)
                         ->get();

        $final = collect();
        foreach($appointmentSummary as $summary){
            $selectedDetail = [];
            foreach($appointmentDetail as $detail){
                if($summary->appointmentID == $detail->appointmentID && $detail->isActive == 1){
                    $selectedStaff = null;
                    foreach($staffs as $staff){
                        if($detail->staffID == $staff->ID){
                            $selectedStaff = $staff;
                            break;
                        }
                    }
                    $detail->selectedStaff = $selectedStaff;
                    $detail->membershipTracker['membershipID'] = $detail->membershipID != 0 ?$detail->membershipID:-1;
                    $detail->membershipTracker['membershipVariantID'] = $detail->membershipVariantID != 0 ?$detail->membershipVariantID: -1;
                    $detail->membershipTracker['purchasedOrderID'] = $detail->purchasedOrderID;
                    $detail->membershipTracker['purchasedOrderSubID'] = $detail->purchasedOrderSubID;
                    $detail->membershipTracker['purchasedStoreID'] = $detail->purchasedStoreID != 0 ?$detail->purchasedStoreID:-1;
                    array_push($selectedDetail,$detail);
                }
            }

            $selectedCustomer = null;

            foreach($customers as $customer){
                if($summary->customerID == $customer->customerID){
                    $selectedCustomer = $customer;
                    break;
                }
            }



            $summary->detail = $selectedDetail;
            $summary->customer = $selectedCustomer;
            $final->push($summary);
        }
        $response['status'] = true;
        $response['data'] = $final;
        return response()->json($response,200,[],JSON_NUMERIC_CHECK);
    }
