{"name":"validate","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Appointment.Appointment.validate","label":"Method","file_path":"/Users/naman/Documents/QBApps/qbapi/app/Appointment.php","start_line":575,"end_line":672,"source":"    public function validate($request, $isUpdate = false, $timezone = null, $chainID)
    {
        $response['status'] = false;
        $isNewCustomer = 0;
        $rules = [
            'storeID' => 'required',
            'creationMode' => 'required',
            'appointmentDuration' => 'required',
            'appointmentDurationUnit' => 'required',
            'detail' => 'required|array',
            'cancellationReason' => 'required_if:status,CANCELLED',
            'repeatCount' => 'required_if:creationMode,REPEAT',
            'repeatFrequency' => 'required_if:creationMode,REPEAT',
            'startTimeLocal' => 'required',
            'endTimeLocal' => 'required',
            'createdBy' => 'required',
            'appointmentIDArray' => 'required|array'
        ];
        if($isUpdate){
            $rules['appointmentID'] = 'required';
            unset($rules['creationMode']);
            unset($rules['repeatCount']);
            unset($rules['repeatFrequency']);
        }
        $validator = Validator::make($request->all(), $rules);

        if ($validator->fails()) {
            $response['status'] = false;
            $response['message'] = $validator->messages()->first();
            return $response;
        }

        if(!in_array($request->creationMode,$this->supportedCreationMode)){
            $response['message'] = "Unsupported creation mode $request->creationMode";
            return $response;
        }

        $serviceTable = Constants::getChainLevelProductsName($chainID, 'products');
        $servicesID = collect(DB::table($serviceTable)->where('productType','SERVICE')->select('productID')->get())->pluck('productID');

        $detailRule = [
            'serviceID' => 'required|in:'.$servicesID->implode(','),
            'serviceName' => 'required',
            'categoryID' => 'required',
            'servicePrice' => 'required',
            'appointmentSubID' => 'required',
            'startTimeLocal' => 'required',
            'endTimeLocal' => 'required'
        ];

        $estimatedCost = 0;

        foreach (collect($request->detail) as $item){

            $validator = Validator::make($item,$detailRule);
            if ($validator->fails()) {
                $response['message'] = $validator->messages()->first();
                return $response;
            }
            $estimatedCost += $item['servicePrice'];
        }

        $status = array();
        $status["status"] = true;
        $status['customers'] = -1;

        if (isset($request->customers)) {
            $dataArray = convertToArray(json_decode($request->getContent()));

            if(!isset($request->createTimeLocal) || empty($request->createTimeLocal)){
                $createTimeLocal = date('Y-m-d H:i:s');
            }else{
                $createTimeLocal = $request->createTimeLocal;
            }

            if(isset($dataArray['timezone'])){
                $timezone = $dataArray['timezone'];
            }

            if($timezone == NULL || $timezone == ''){
                $timezone = Constants::getChainTimezone($chainID);
            }

            $dataArray['billSettledTimeLocal'] = $createTimeLocal;
            $dataArray['timezone'] = $timezone;

            $status = Order::customersOrder($request->storeID, $dataArray, $status);
            $customer1 = $status["customers"];
            $isNewCustomer = $status["isNewCustomer"];
        }else{
            $customer1 = NULL;
        }

        $response['status'] = true;
        $response['estimatedCost'] = $estimatedCost;
        $response['customerID'] = (int)$status['customers'];
        return $response;
    }
