{"name":"requestTracker","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Http.Controllers.thirdPartyController.thirdPartyController.requestTracker","label":"Method","file_path":"/Users/naman/Documents/QBApps/qbapi/app/Http/Controllers/thirdPartyController.php","start_line":2015,"end_line":2074,"source":"      public static function requestTracker($chainID,$dataArray){
        $listOfChainsTable = Constants::getGlobalTableName("listOfChains");
        // get default thirdPartyChain ID
        $getDefaultThirdPartyChainID = convertToArray(DB::table($listOfChainsTable)->select('defaultSuperChainForIntegration')->where('chainID',$chainID)->get());
        if(isset($getDefaultThirdPartyChainID[0]['defaultSuperChainForIntegration']) && $getDefaultThirdPartyChainID[0]['defaultSuperChainForIntegration'] > 0){
            $thirdPartyChainID = $getDefaultThirdPartyChainID[0]['defaultSuperChainForIntegration'];
        } else{
            $thirdPartyChainID = $dataArray['thirdPartyChainID'];
        }
        if(!isset($dataArray["apiTrackerID"]) || $dataArray["apiTrackerID"] == "NA" || $dataArray["apiTrackerID"] == null || $dataArray["apiTrackerID"] == ""){
            //fetch tracker ID from database
            $globalThirdPartyAPIUsageTrackerTable = Constants::getGlobalTableName("globalThirdPartyAPIUsageTracker");
            $apiTrackerID = convertToArray(DB::table($globalThirdPartyAPIUsageTrackerTable)->where('status', 'ACTIVE')->where('thirdPartyChainID', $thirdPartyChainID)->first())['apiTrackerID'];
            if(!empty($apiTrackerID)){
                $dataArray["apiTrackerID"] = $apiTrackerID;
            }
        }else{
            $apiTrackerID = $dataArray["apiTrackerID"];
        }
        $apiTrackerArray = array();
        $responseTime = (microtime(true) - LARAVEL_START)*1000;
        $apiTrackerArray["responseTime"] = $responseTime;
        $memoryUsage = memory_get_usage()/1024/1024;
        $apiTrackerArray["memoryUsage"] = $memoryUsage;
        $apiTrackerArray["token"] = $dataArray["Authorization"];
        $apiTrackerArray["apiName"] = $dataArray['apiName'];
        $apiTrackerArray["apiPath"] = $dataArray['apiPath'];
        $apiTrackerArray["apiMethod"] = $dataArray['apiMethod'];
        $apiTrackerArray['remarks'] = $dataArray['remarks'];
        $apiTrackerArray["apiTrackerID"] = isset($dataArray["apiTrackerID"])?$dataArray["apiTrackerID"]:"NA";
        $apiTrackerArray["thirdPartyChainID"] = $thirdPartyChainID;
        $apiTrackerArray['chainID'] = $chainID;
        $apiTrackerArray['storeID'] = isset($dataArray["storeID"]) ? $dataArray["storeID"] : 0;
        $apiTrackerArray["statusCode"] = $dataArray["status"] == true ? 200 : 422;
        $apiTrackerArray["timezone"] = "Asia/Kolkata";
        date_default_timezone_set($apiTrackerArray["timezone"]);
        $apiTrackerArray["serverRequestTimeLocal"] = date("Y-m-d H:i:s");

        date_default_timezone_set("UTC");
        $apiTrackerArray["serverRequestTimeUTC"] = date("Y-m-d H:i:s");
        $apiTrackerArray['clientIP'] = $dataArray['clientIP'];
        $globalThirdPartyAPIUsageTrackerTable = Constants::getGlobalTableName("globalThirdPartyAPIUsageTracker");
        $globalThirdPartyAPICallLogsTable = Constants::getGlobalTableName("globalThirdPartyAPICallLogs");

        // add requestPayload & responsePayload
        $apiTrackerArray['requestPayload'] = isset($dataArray['requestPayload']) ? $dataArray['requestPayload'] : NULL;
        $apiTrackerArray['responsePayload'] = isset($dataArray['responsePayload']) ? $dataArray['responsePayload'] : NULL;


        if ($apiTrackerArray["apiTrackerID"] != "NA") {
            DB::transaction(function()use($apiTrackerArray,$globalThirdPartyAPIUsageTrackerTable,$globalThirdPartyAPICallLogsTable){
                DB::table($globalThirdPartyAPICallLogsTable)->insert($apiTrackerArray);
                $thirdPartyChainID = intval($apiTrackerArray["thirdPartyChainID"]);
                $apiTrackerID = $apiTrackerArray["apiTrackerID"];
                DB::statement("UPDATE $globalThirdPartyAPIUsageTrackerTable SET apiCallsConsumed = apiCallsConsumed +1 WHERE thirdPartyChainID = '$thirdPartyChainID' AND apiTrackerID = '$apiTrackerID'");
            });

        }

      }
